const values = $.steps.fetchData.response.values || [];
if (values.length === 0) return { dataText: 'No data found in spreadsheet.', rowCount: 0, colCount: 0 };
const headers = values[0];
const rows = values.slice(1);
let dataText = 'COLUMNS: ' + headers.join(', ') + '\n';
dataText += 'TOTAL ROWS: ' + rows.length + '\n\n';
dataText += 'SAMPLE DATA (first 50 rows):\n';
rows.slice(0, 50).forEach((row, i) => {
  const obj = {};
  headers.forEach((h, j) => { obj[h] = row[j] || ''; });
  dataText += JSON.stringify(obj) + '\n';
});
if (rows.length > 50) dataText += '\n... (' + (rows.length - 50) + ' more rows not shown)\n';
return { dataText, rowCount: rows.length, colCount: headers.length, headers };

const prompt = `You are an expert data analyst. Analyze the following dataset and answer the user's question.

USER QUESTION: ${$.input.question}

DATASET:
${$.steps.prepareData.output.dataText}

Provide a thorough analysis that includes:
1. Direct answer to the question
2. Key data points and statistics that support your answer
3. Any notable patterns or trends
4. Actionable recommendations based on the data

Return ONLY valid JSON:
{
  "answer": "Direct answer to the question",
  "key_findings": ["finding 1", "finding 2", "finding 3"],
  "statistics": [
    { "metric": "metric name", "value": "metric value" }
  ],
  "trends": "Notable patterns or trends observed",
  "recommendations": ["recommendation 1", "recommendation 2"]
}`;
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { answer: raw, key_findings: [], statistics: [], trends: '', recommendations: [] }; }

const ai = $.steps.parseAI.output || {};
const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Data Analysis Report' } });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Question:* ' + $.input.question } });
blocks.push({ type: 'divider' });
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Answer*\n' + (ai.answer || 'No answer generated.') } });
blocks.push({ type: 'divider' });
if (ai.key_findings && ai.key_findings.length > 0) {
  let findingsText = '*Key Findings*\n';
  ai.key_findings.forEach((f, i) => { findingsText += (i+1) + '. ' + f + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: findingsText } });
}
if (ai.statistics && ai.statistics.length > 0) {
  const fields = ai.statistics.slice(0, 10).map(s => ({ type: 'mrkdwn', text: '*' + s.metric + '*\n' + s.value }));
  for (let i = 0; i < fields.length; i += 2) {
    blocks.push({ type: 'section', fields: fields.slice(i, i + 2) });
  }
}
blocks.push({ type: 'divider' });
if (ai.trends) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Trends & Patterns*\n' + ai.trends } });
}
if (ai.recommendations && ai.recommendations.length > 0) {
  let recsText = '*Recommendations*\n';
  ai.recommendations.forEach((r, i) => { recsText += (i+1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recsText } });
}
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Dataset: ' + $.steps.prepareData.output.rowCount + ' rows x ' + $.steps.prepareData.output.colCount + ' columns' }] });
const fallback = 'Data Analysis: ' + $.input.question;
return { blocks, fallback };
